'contact information' includes email addresses;
'extent of their access rights' indicates the number of permissions each administrator holds.

sql:
SELECT maintenance_frequency, COUNT(*)
FROM maintenance_schedules
GROUP BY maintenance_frequency;

SELECT building_name
FROM buildings
WHERE building_id IN (SELECT DISTINCT building_id FROM energy_audits);

SELECT COUNT(building_id) AS NumberOfBuildings
FROM building_energy_efficiency
WHERE energy_rating > 3.5;

SELECT COUNT(DISTINCT building_id)
FROM maintenance_schedules
WHERE strftime('%m', schedule_date) = strftime('%m', 'now');
